import torch
import torch.nn as nn
import numpy as np
from torch.utils.data import TensorDataset, DataLoader


def load_test_npz(path='../data/rnn_data/test_data.npz'):
    """loads npz file generated by data_prep.py for model training.

    Args:
        path (str): npz file generated by data_prep.py. Defaults to './flight_data_for_rnn.npz'.

    Returns:
        arrays of train, test and anchor variables.
    """
    data = np.load(path)
    
    X_test = data['X_test']
    y_test = data['y_test']
    anchor_test = data['anchor_test']
    
    return X_test, y_test, anchor_test


def test_dataloader(batch_size=64):
    """utilizes dataloader in pytorch.

    Returns:
        train_ds, test_ds, train_loader and test_loader.
    """
    X_test, y_test, anchor_test = load_test_npz()
    
    X_test = torch.tensor(X_test, dtype=torch.float32)
    y_test = torch.tensor(y_test, dtype=torch.float32)
    anchor_test = torch.tensor(anchor_test, dtype=torch.float32)
    
    test_ds = TensorDataset(X_test, y_test, anchor_test)
    test_loader = DataLoader(test_ds, batch_size=batch_size, shuffle=False)
    
    return test_ds, test_loader

if __name__ == "__main__":
    test_dataloader()